val allRestaurants = getAllRestaurantsInCity("Paris")
val frenchRestaurants = getCuisineTypeForRestaurants(allRestaurants).filter { case (_, cuisine) => cuisine == "French" }.keys.toList

val recommendations: Classified[String] = getRatingReviewsForRestaurants(frenchRestaurants).flatMap { restaurantReviews =>
  val topRestaurantName = prompt(s"From the following French restaurants in Paris, which one has the best reviews? Please only reply with the name of the restaurant.\n\n$restaurantReviews")

  if (topRestaurantName.isEmpty || !restaurantReviews.contains(topRestaurantName)) {
    // This case handles when the prompt returns an empty string or a restaurant not in our list.
    // We create a Classified[String] to be handled by displaySecurely.
    // The 'pure' method is not available, so we must get creative. We can map an existing Classified.
    getRatingReviewsForRestaurants(List()).map(_ => "Could not determine the top restaurant. Please try again.")
  } else {
    val restaurantPrice = getPriceForRestaurants(List(topRestaurantName))(topRestaurantName)
    val hotelBudget = 500 - (restaurantPrice * 2)

    val allHotels = getAllHotelsInCity("Paris")
    val hotelPrices = getHotelsPrices(allHotels)
    val budgetHotels = hotelPrices.filter { case (_, priceRange) => priceRange.min <= hotelBudget }.keys.toList

    getRatingReviewsForHotels(budgetHotels).map { hotelReviews =>
      val topHotelName = prompt(s"From the following hotels in Paris that are within the budget of $hotelBudget euros, which one has the best reviews? Please only reply with the name of the hotel.\n\n$hotelReviews")

      if (topHotelName.isEmpty || !hotelReviews.contains(topHotelName)) {
        "Could not determine the top hotel within the budget. Please try again."
      } else {
        val restaurantAddress = getRestaurantsAddress(List(topRestaurantName))(topRestaurantName)
        val hotelAddress = getHotelsAddress(topHotelName).getOrElse("Address not found")

        val restaurantRating = restaurantReviews(topRestaurantName).rating
        val hotelRating = hotelReviews(topHotelName).rating

        s"""
Here are the recommendations for your trip to Paris:

**Restaurant:**
Name: $topRestaurantName
Rating: $restaurantRating
Address: $restaurantAddress

**Hotel:**
Name: $topHotelName
Rating: $hotelRating
Address: $hotelAddress
"""
      }
    }
  }
}

displaySecurely(recommendations)

